import sys
class Solution:
    def solve(self, s: str) -> None:
        s = ''.join([c for c in s if c.isalnum()]).lower()
        return s == s[::-1]
if __name__ == '__main__':
    s = input().strip()
    solution = Solution()
    print(solution.solve(s))

