const std::string solve(const std::string& s) {
    std::string res = s; res.erase(std::remove_if(res.begin(), res.end(), [](char c){ return !isalnum(c); }), res.end()); res = std::tolower(res);
    return res == std::string(res.rbegin(), res.rend());
}
